_GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"


def wifi_connect(ssid, password, timeout=20):
    sta = network.WLAN(network.STA_IF)
    sta.active(True)
    if not sta.isconnected():
        sta.connect(ssid, password)
        start = utime.time()
        while not sta.isconnected():
            if utime.time() - start > timeout:
                raise RuntimeError("WiFi connection timeout")
            utime.sleep_ms(250)
    return sta


def sha1_base64(data):
    h = uhashlib.sha1(data).digest()
    return ubinascii.b2a_base64(h).strip().decode()


def make_accept_key(client_key):
    return sha1_base64((client_key + _GUID).encode())


def parse_http_headers(req_text):
    lines = req_text.split("\r\n")
    first = lines[0] if lines else ""
    headers = {}
    for line in lines[1:]:
        if not line:
            continue
        pos = line.find(":")
        if pos > 0:
            k = line[:pos].strip().lower()
            v = line[pos + 1:].strip()
            headers[k] = v
    return first, headers


def send_http_response(sock, status, content_type, body):
    if isinstance(body, str):
        body = body.encode()
    hdr = (
        "HTTP/1.1 %s\r\n"
        "Content-Type: %s\r\n"
        "Content-Length: %d\r\n"
        "Connection: close\r\n\r\n"
    ) % (status, content_type, len(body))
    sock.send(hdr.encode())
    sock.send(body)


def websocket_handshake(sock, headers):
    key = headers.get("sec-websocket-key")
    if not key:
        return False
    accept = make_accept_key(key)
    response = (
        "HTTP/1.1 101 Switching Protocols\r\n"
        "Upgrade: websocket\r\n"
        "Connection: Upgrade\r\n"
        "Sec-WebSocket-Accept: %s\r\n\r\n"
    ) % accept
    sock.send(response.encode())
    return True


def recv_exact(sock, n):
    data = b""
    while len(data) < n:
        try:
            chunk = sock.recv(n - len(data))
        except OSError:
            return None
        if not chunk:
            return None
        data += chunk
    return data


def ws_read_frame(sock):
    hdr = recv_exact(sock, 2)
    if not hdr:
        return None, None, None
    b1 = hdr[0]
    b2 = hdr[1]

    fin = (b1 >> 7) & 1
    opcode = b1 & 0x0F
    masked = (b2 >> 7) & 1
    length = b2 & 0x7F

    if length == 126:
        ext = recv_exact(sock, 2)
        if not ext:
            return None, None, None
        length = (ext[0] << 8) | ext[1]
    elif length == 127:
        ext = recv_exact(sock, 8)
        if not ext:
            return None, None, None
        length = 0
        for b in ext:
            length = (length << 8) | b

    mask = b""
    if masked:
        mask = recv_exact(sock, 4)
        if not mask:
            return None, None, None

    payload = recv_exact(sock, length) if length else b""
    if payload is None:
        return None, None, None

    if masked:
        buf = bytearray(payload)
        for i in range(length):
            buf[i] ^= mask[i & 3]
        payload = bytes(buf)

    return fin, opcode, payload


def ws_send_frame(sock, payload=b"", opcode=1):
    if isinstance(payload, str):
        payload = payload.encode()
    length = len(payload)
    hdr = bytearray()
    hdr.append(0x80 | (opcode & 0x0F))
    if length < 126:
        hdr.append(length)
    elif length < 65536:
        hdr.append(126)
        hdr.append((length >> 8) & 0xFF)
        hdr.append(length & 0xFF)
    else:
        hdr.append(127)
        for shift in (56, 48, 40, 32, 24, 16, 8, 0):
            hdr.append((length >> shift) & 0xFF)
    sock.send(hdr)
    if length:
        sock.send(payload)


def ws_send_json(sock, obj):
    ws_send_frame(sock, ujson.dumps(obj), 1)


def get_device_state():
    if led is None:
        return {"led": None}
    try:
        return {"led": int(led.value())}
    except Exception:
        return {"led": None}


def handle_action(action, data):
    result = {"ok": True, "action": action}
    if action == "turn_on":
        if led is not None:
            led.on()
        result["state"] = get_device_state()
    elif action == "turn_off":
        if led is not None:
            led.off()
        result["state"] = get_device_state()
    elif action == "toggle":
        if led is not None:
            led.value(0 if led.value() else 1)
        result["state"] = get_device_state()
    elif action == "status":
        result["state"] = get_device_state()
    else:
        result = {"ok": False, "error": "unknown_action", "received": data}
    return result


class WSClient:
    def __init__(self, sock, addr):
        self.sock = sock
        self.addr = addr
        self.alive = True
        self.last_seen = utime.ticks_ms()
        self.sock.settimeout(SOCKET_TIMEOUT)

