def read_http_request(sock):
    data = b""
    while b"\r\n\r\n" not in data:
        chunk = sock.recv(512)
        if not chunk:
            break
        data += chunk
        if len(data) > 4096:
            break
    return data.decode(errors="ignore")


def handle_new_connection(client_sock, addr, clients):
    client_sock.settimeout(2)
    try:
        req = read_http_request(client_sock)
        if not req:
            client_sock.close()
            return
        first_line, headers = parse_http_headers(req)
        parts = first_line.split(" ")
        method = parts[0] if len(parts) > 0 else ""
        path = parts[1] if len(parts) > 1 else "/"

        if method != "GET":
            send_http_response(client_sock, "405 Method Not Allowed", "text/plain", "Method Not Allowed")
            client_sock.close()
            return

        upgrade = headers.get("upgrade", "").lower()
        if path == "/ws" and upgrade == "websocket":
            if len(clients) >= MAX_CLIENTS:
                send_http_response(client_sock, "503 Service Unavailable", "text/plain", "Too many clients")
                client_sock.close()
                return
            if websocket_handshake(client_sock, headers):
                client = WSClient(client_sock, addr)
                clients.append(client)
                client.send_json({"ok": True, "message": "connected", "state": get_device_state()})
            else:
                send_http_response(client_sock, "400 Bad Request", "text/plain", "Bad WebSocket Request")
                client_sock.close()
        elif path == "/" or path == "/index.html":
            send_http_response(client_sock, "200 OK", "text/html; charset=utf-8", HTML_PAGE)
            client_sock.close()
        else:
            send_http_response(client_sock, "404 Not Found", "text/plain", "Not Found")
            client_sock.close()
    except Exception:
        try:
            client_sock.close()
        except Exception:
            pass


